code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Card, Badge, Avatar, Chip, Button, icon } from 'decantr/components';

code.example:
function EcosystemGrid({ items }) {
  const { div, h3, span, a } = tags;

  return div({ class: css('_flex _col _gap8') },
    // Header
    div({ class: css('_flex _jcsb _aic') },
      h3({ class: css('_heading4') }, 'Community Registry'),
      Button({ variant: 'outline' }, icon('plus'), 'Publish Your Own')
    ),
    // Grid
    div({ class: css('_grid _gc1 _md:gc2 _lg:gc3 _gap6') },
      ...items.map(item =>
        Card({ hoverable: true, class: css('d-glass') },
          Card.Body({ class: css('_flex _col _gap3') },
            div({ class: css('_flex _jcsb _aic') },
              Chip({ size: 'sm', variant: item.type === 'style' ? 'primary' : 'secondary' }, item.type),
              span({ class: css('_textsm _fgmuted') }, `${item.downloads} downloads`)
            ),
            h3({ class: css('_heading5') }, item.name),
            span({ class: css('_textsm _fgmuted') }, item.description),
            div({ class: css('_flex _aic _gap2 _mt[auto] _pt3 _borderT _bcborder') },
              Avatar({ src: item.author.avatar, size: 'xs' }),
              span({ class: css('_textsm _fgmuted') }, `@${item.author.username}`)
            )
          )
        )
      )
    ),
    // Footer CTA
    div({ class: css('_tc') },
      Button({ variant: 'primary' }, 'Browse Full Registry', icon('arrow-right'))
    )
  );
}

